import React, { Component } from 'react';
import './normalize.css';
import './App.css';

function NavBar(props){
  // for the buttons basically
  let buttons = [
    {key: "Resume"},
    {key: "About"},
    {key: "Projects"},
  ]
  return (
    <nav>
      <div id="nav-links">
        <p>Gabe Ochoa</p>
        {buttons.map((item, i) => {
          return (<button key={item.key} 
                          name={i}
                         onClick={props.onClick}
                         className={props.selected === i? "underlined" : ""}>
                  {item.key}
                  </button>);
        })
        }
      </div>
    </nav>
  );
}

class App extends Component {

  constructor(props){
    super(props);
    this.state = {
      current_tab: 2
    }
  }

  render() {
    return (
      <div className="App">
        <header className="App-header">
          <NavBar
            onClick={(event)=>{this.setState({current_tab: parseInt(event.target.getAttribute("name"))})}}
            selected={this.state.current_tab}
          />
          <h6>
            Senior Software Eng. @ Bloomberg L.P.
            <br/>
            <sup>Previously CS &amp; Math @ Binghamton University</sup>
          </h6>
        </header>
        <section className="App-content">
          <h1>Projects:</h1>
        </section>
        <footer className="App-footer">
          <h1>Let's get in touch!</h1>
        </footer>
      </div>
    );
  }
}

export default App;
